package ratelimit

import (
	"sync"
	"time"
)

type entry struct {
	count    int
	firstReq time.Time
}

type Store struct {
	mu      sync.Mutex
	entries map[string]*entry
	window  time.Duration
	stop    chan struct{}
}

func NewStore(window time.Duration) *Store {
	s := &Store{
		entries: make(map[string]*entry),
		window:  window,
		stop:    make(chan struct{}),
	}
	go s.cleanup()
	return s
}

func (s *Store) Increment(key string) int {
	s.mu.Lock()
	defer s.mu.Unlock()
	e, ok := s.entries[key]
	if !ok || time.Since(e.firstReq) > s.window {
		s.entries[key] = &entry{count: 1, firstReq: time.Now()}
		return 1
	}
	e.count++
	return e.count
}

func (s *Store) cleanup() {
	ticker := time.NewTicker(60 * time.Second)
	defer ticker.Stop()
	for {
		select {
		case <-ticker.C:
			s.mu.Lock()
			now := time.Now()
			for key, e := range s.entries {
				if now.Sub(e.firstReq) > s.window {
					delete(s.entries, key)
				}
			}
			s.mu.Unlock()
		case <-s.stop:
			return
		}
	}
}

func (s *Store) Close() {
	close(s.stop)
}
